// Define Interface for Source Product in Import Tool
interface SourceProduct {
    id: string;
    name: string;
    sku: string;
    price: number;
    stock: number;
    image: string;
    weight: number;
    description: string;
    status: 'active' | 'inactive';
    existsInOmni: boolean; // Is SKU already in OmniSales?
    isCopied: boolean; // Has been copied in this session?
    variantsCount: number; // Added: Number of variants
}

// Define Interface for Sync History
interface SyncHistoryItem {
    id: string;
    sourceShopName: string;
    targetCount: number;
    timestamp: string;
    status: 'success' | 'failed' | 'partial';
    productsSynced: number;
}

// Define Interface for Import History
interface ImportHistoryItem {
    id: string;
    sourceShopName: string;
    targetWarehouseName: string;
    productCount: number;
    timestamp: string;
    status: 'success' | 'failed';
    details: SourceProduct[]; // Added details to history
}

const Tools: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'import' | 'listing' | 'sync' | 'bulkedit' | 'keywords'>('import');

  // Listing State
  const [listingFilter, setListingFilter] = useState('all');
  const [isListingModalOpen, setIsListingModalOpen] = useState(false);
  const [listingStep, setListingStep] = useState(1); // 1: Source, 2: Target, 3: Product, 4: Edit
  const [listingSource, setListingSource] = useState<'system' | 'shop' | 'link'>('system');
  const [listingSelectedShops, setListingSelectedShops] = useState<string[]>([]);
  const [listingSelectedProducts, setListingSelectedProducts] = useState<string[]>([]);
  const [listingLinkUrl, setListingLinkUrl] = useState('');
  const [isAnalyzingLink, setIsAnalyzingLink] = useState(false);

  // Listing Edit State (Existing Products)
  const [editingListing, setEditingListing] = useState<any | null>(null);
  const [showFilterPanel, setShowFilterPanel] = useState(false);

  // Listing Wizard Edit State (Step 4)
  const [listingEdits, setListingEdits] = useState<Record<string, { price: number, stock: number }>>({});

  // Publishing Progress State
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishProgress, setPublishProgress] = useState(0);
  const [publishStatus, setPublishStatus] = useState<'processing' | 'success'>('processing');

  // Shop Sync State
  const [syncConfig, setSyncConfig] = useState({
    sourceShopId: '',
    targetShopIds: [] as string[],
    syncStock: true,
    syncPrice: true,
    syncInfo: false,
  });
  // New State for Sync Logic
  const [showSyncModal, setShowSyncModal] = useState(false);
  const [syncProgress, setSyncProgress] = useState(0);
  const [syncHistory, setSyncHistory] = useState<SyncHistoryItem[]>([
      { id: 'h1', sourceShopName: 'Shop Mẹ & Bé Official', targetCount: 2, timestamp: '12/05/2025 10:30', status: 'success', productsSynced: 150 },
      { id: 'h2', sourceShopName: 'Kho Sỉ Thời Trang', targetCount: 1, timestamp: '10/05/2025 14:15', status: 'partial', productsSynced: 45 }
  ]);

  // Import State (Redesigned)
  const [importConfig, setImportConfig] = useState({
      sourceShopId: '',
      targetWarehouseId: MOCK_WAREHOUSES[0].id,
      pricePolicy: 'retail' as 'retail' | 'wholesale' | 'import'
  });
  const [sourceProducts, setSourceProducts] = useState<SourceProduct[]>([]);
  const [selectedImportIds, setSelectedImportIds] = useState<string[]>([]);

  // Initial Mock History with details
  const [importHistory, setImportHistory] = useState<ImportHistoryItem[]>([
      { 
          id: 'ih1', 
          sourceShopName: 'Shop Mẹ & Bé Official', 
          targetWarehouseName: 'Kho Tổng TP.HCM', 
          productCount: 5, 
          timestamp: '15/05/2025 08:30', 
          status: 'success',
          details: MOCK_PRODUCTS.slice(0, 5).map(p => ({
              id: `hist-${p.id}`, name: p.name, sku: p.sku, price: p.price, stock: p.stock, image: p.image, 
              weight: 500, description: p.description, status: 'active', existsInOmni: true, isCopied: true, variantsCount: 2
          }))
      },
      { 
          id: 'ih2', 
          sourceShopName: 'Kho Sỉ Thời Trang', 
          targetWarehouseName: 'Kho Hà Nội', 
          productCount: 12, 
          timestamp: '14/05/2025 14:15', 
          status: 'success',
          details: MOCK_PRODUCTS.slice(5, 17).map(p => ({
              id: `hist-${p.id}`, name: p.name, sku: p.sku, price: p.price, stock: p.stock, image: p.image, 
              weight: 500, description: p.description, status: 'active', existsInOmni: true, isCopied: true, variantsCount: 0
          }))
      }
  ]);

  // New state for history details modal
  const [selectedHistoryItem, setSelectedHistoryItem] = useState<ImportHistoryItem | null>(null);

  // Import Process State
  const [importProgress, setImportProgress] = useState(0);
  const [showProgressModal, setShowProgressModal] = useState(false);
  const [importStatus, setImportStatus] = useState<'processing' | 'success'>('processing');
  const [copiedCount, setCopiedCount] = useState(0);

  // Bulk Edit State
  const [bulkEditConfig, setBulkEditConfig] = useState<{type: 'percent_inc' | 'percent_dec' | 'amount_inc' | 'amount_dec', value: number}>({ type: 'percent_inc', value: 0 });
  const [bulkEditSearch, setBulkEditSearch] = useState('');
  const [selectedBulkEditProducts, setSelectedBulkEditProducts] = useState<string[]>([]);
  const [priceHistory, setPriceHistory] = useState(MOCK_PRICE_HISTORY);

  // Forbidden Keywords State
  const [keywordsList, setKeywordsList] = useState(MOCK_FORBIDDEN_KEYWORDS);
  const [selectedCategory, setSelectedCategory] = useState<string>('Thương hiệu/MXH');
  const [isKeywordModalOpen, setIsKeywordModalOpen] = useState(false);
  const [keywordForm, setKeywordForm] = useState({ id: '', text: '', category: '' });

  // Flatten shops list for selection
  const allShops = INITIAL_INTEGRATIONS.flatMap(i => i.shops.map(s => ({ ...s, platform: i.platform })));

  const tabs = [
    { id: 'import', label: 'Sao chép sản phẩm', icon: Download },
    { id: 'listing', label: 'Đăng bán sản phẩm', icon: UploadCloud },
    { id: 'sync', label: 'Đồng bộ Shop chéo', icon: ArrowRightLeft },
    { id: 'bulkedit', label: 'Sửa giá hàng loạt', icon: Edit3 },
    { id: 'keywords', label: 'Từ khóa cấm', icon: ShieldBan },
  ];

  const handleStartSync = () => {
    if (!syncConfig.sourceShopId) {
      alert("Vui lòng chọn Shop nguồn.");
      return;
    }
    if (syncConfig.targetShopIds.length === 0) {
      alert("Vui lòng chọn ít nhất 1 Shop đích.");
      return;
    }

    setShowSyncModal(true);
    setSyncProgress(0);

    // Simulate Sync Process
    const totalTime = 3000;
    const intervalTime = 50;
    const steps = totalTime / intervalTime;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
      setSyncProgress(progress);

      if (currentStep >= steps) {
        clearInterval(timer);

        // Add to history
        const sourceShop = allShops.find(s => s.id === syncConfig.sourceShopId);
        const newHistoryItem: SyncHistoryItem = {
            id: `h-${Date.now()}`,
            sourceShopName: sourceShop ? sourceShop.name : 'Unknown',
            targetCount: syncConfig.targetShopIds.length,
            timestamp: new Date().toLocaleString('vi-VN'),
            status: 'success',
            productsSynced: Math.floor(Math.random() * 200) + 10 // Mock number
        };
        setSyncHistory(prev => [newHistoryItem, ...prev]);

        // Don't close immediately, let user see 100%
      }
    }, intervalTime);
  };

  const toggleTargetShop = (shopId: string) => {
    setSyncConfig(prev => {
      const exists = prev.targetShopIds.includes(shopId);
      return {
        ...prev,
        targetShopIds: exists 
          ? prev.targetShopIds.filter(id => id !== shopId)
          : [...prev, shopId]
      };
    });
  };

  const toggleAllTargets = () => {
      const availableTargets = allShops.filter(s => s.id !== syncConfig.sourceShopId);
      const allSelected = availableTargets.length > 0 && availableTargets.every(s => syncConfig.targetShopIds.includes(s.id));

      if (allSelected) {
          setSyncConfig(prev => ({ ...prev, targetShopIds: [] }));
      } else {
          setSyncConfig(prev => ({ ...prev, targetShopIds: availableTargets.map(s => s.id) }));
      }
  };

  // --- Import Logic ---
  // Simulate fetching products from a shop
  useEffect(() => {
      if (importConfig.sourceShopId) {
          const mockSource: SourceProduct[] = MOCK_PRODUCTS.slice(0, 15).map(p => {
              const hasSku = Math.random() > 0.2; 
              const exists = hasSku && Math.random() > 0.5; 

              return {
                  id: `src-${p.id}`,
                  name: p.name,
                  sku: hasSku ? p.sku : '', 
                  price: p.price,
                  stock: p.stock,
                  image: p.image,
                  weight: 500,
                  description: p.description,
                  status: 'active',
                  existsInOmni: exists,
                  isCopied: false,
                  variantsCount: Math.random() > 0.6 ? Math.floor(Math.random() * 5) + 2 : 0 // Random 0 or 2-6 variants
              };
          });

          // SORTING: Priority for valid copy candidates
          mockSource.sort((a, b) => {
              const canCopyA = !!a.sku && !a.existsInOmni && !a.isCopied;
              const canCopyB = !!b.sku && !b.existsInOmni && !b.isCopied;

              if (canCopyA && !canCopyB) return -1;
              if (!canCopyA && canCopyB) return 1;
              return 0;
          });

          setSourceProducts(mockSource);
          setSelectedImportIds([]);
      } else {
          setSourceProducts([]);
      }
  }, [importConfig.sourceShopId]);

  const toggleImportSelection = (id: string) => {
      setSelectedImportIds(prev => 
          prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
      );
  };

  const handleCopyProducts = () => {
      const count = selectedImportIds.length;
      if (count === 0) return alert("Vui lòng chọn sản phẩm để sao chép.");

      setCopiedCount(count);
      setShowProgressModal(true);
      setImportStatus('processing');
      setImportProgress(0);

      const totalTime = 2000; 
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setImportProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);
              setImportStatus('success');

              const copiedItems = sourceProducts.filter(p => selectedImportIds.includes(p.id)).map(p => ({
                  ...p, isCopied: true, existsInOmni: true
              }));

              setSourceProducts(prev => prev.map(p => 
                  selectedImportIds.includes(p.id) ? { ...p, isCopied: true, existsInOmni: true } : p
              ));

              // Add to history with details
              const sourceShopName = allShops.find(s => s.id === importConfig.sourceShopId)?.name || 'Unknown';
              const targetWarehouseName = MOCK_WAREHOUSES.find(w => w.id === importConfig.targetWarehouseId)?.name || 'Unknown';
              const newHistory: ImportHistoryItem = {
                  id: `imp-${Date.now()}`,
                  sourceShopName,
                  targetWarehouseName,
                  productCount: count,
                  timestamp: new Date().toLocaleString('vi-VN'),
                  status: 'success',
                  details: copiedItems
              };
              setImportHistory(prev => [newHistory, ...prev]);

              setSelectedImportIds([]); 
          }
      }, intervalTime);
  };

  // --- Listing Wizard Handlers ---
  const toggleListingShop = (shopId: string) => {
    setListingSelectedShops(prev => 
      prev.includes(shopId) ? prev.filter(id => id !== shopId) : [...prev, shopId]
    );
  };

  const toggleListingProduct = (productId: string) => {
    setListingSelectedProducts(prev => 
      prev.includes(productId) ? prev.filter(id => id !== productId) : [...prev, productId]
    );
  };

  const resetListingWizard = () => {
    setIsListingModalOpen(false);
    setListingStep(1);
    setListingSelectedShops([]);
    setListingSelectedProducts([]);
    setListingEdits({});
    setListingLinkUrl('');
    setIsAnalyzingLink(false);
  };

  const handleAnalyzeLink = () => {
      if (!listingLinkUrl) return alert("Vui lòng nhập đường dẫn.");
      setIsAnalyzingLink(true);

      // Simulate API call
      setTimeout(() => {
          setIsAnalyzingLink(false);
          // Set selection to a mock product (simulating finding it)
          setListingSelectedProducts([MOCK_PRODUCTS[0].id]);
          // Move to next step
          setListingStep(2); 
      }, 1500);
  };

  const handleListingEditChange = (id: string, field: 'price' | 'stock', value: string) => {
      let numValue = 0;
      if (field === 'price') {
          // Remove dots for thousand separator
          numValue = parseInt(value.replace(/\./g, '') || '0', 10);
      } else {
          numValue = parseInt(value || '0', 10);
      }

      setListingEdits(prev => ({
          ...prev,
          [id]: { 
              ...prev[id], 
              [field]: numValue 
          }
      }));
  };

  // Helper to format number for input display (e.g. 100000 -> 100.000)
  const formatInputNumber = (value: number) => {
      return new Intl.NumberFormat('vi-VN').format(value);
  };

  const handlePublishListing = () => {
      if (listingSelectedProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");

      // Start Publishing Simulation
      setIsPublishing(true);
      setPublishProgress(0);
      setPublishStatus('processing');

      const totalTime = 3000; // 3 seconds simulation
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setPublishProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);
              setPublishStatus('success');
          }
      }, intervalTime);
  };

  const renderPublishProgressModal = () => {
      if (!isPublishing) return null;

      const productsCount = listingSelectedProducts.length;
      const shopsCount = listingSelectedShops.length;

      return (
          <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm overflow-hidden flex flex-col items-center p-8 text-center">
                  {publishStatus === 'processing' ? (
                      <>
                          <div className="relative w-24 h-24 mb-6">
                              <svg className="animate-spin w-full h-full text-indigo-100" viewBox="0 0 24 24">
                                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                              </svg>
                              <div className="absolute inset-0 flex items-center justify-center text-lg font-bold text-indigo-600">
                                  {publishProgress}%
                              </div>
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đang đẩy sản phẩm...</h3>
                          <p className="text-slate-500 text-sm mb-6">
                              Đang đăng <strong>{productsCount}</strong> sản phẩm lên <strong>{shopsCount}</strong> gian hàng.
                              <br/>
                              <span className="text-red-500 font-medium">Vui lòng không tắt trình duyệt!</span>
                          </p>
                          <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                              <div className="bg-indigo-600 h-full transition-all duration-300 ease-out" style={{width: `${publishProgress}%`}}></div>
                          </div>
                      </>
                  ) : (
                      <>
                          <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 animate-bounce">
                              <Rocket size={40} strokeWidth={2} />
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đăng bán thành công!</h3>
                          <p className="text-slate-500 text-sm mb-6">
                              Yêu cầu đã được gửi đến sàn. Sản phẩm sẽ xuất hiện trong vài phút tới.
                          </p>
                          <button 
                              onClick={() => { setIsPublishing(false); resetListingWizard(); }}
                              className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all shadow-lg"
                          >
                              Hoàn tất
                          </button>
                      </>
                  )}
