        p.name.toLowerCase().includes(bulkEditSearch.toLowerCase()) || 
        p.sku.toLowerCase().includes(bulkEditSearch.toLowerCase())
    );

    const toggleSelection = (id: string) => {
        setSelectedBulkEditProducts(prev => 
            prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
        );
    };

    const toggleSelectAll = () => {
        if (selectedBulkEditProducts.length === filteredProducts.length) {
            setSelectedBulkEditProducts([]);
        } else {
            setSelectedBulkEditProducts(filteredProducts.map(p => p.id));
        }
