    // Calculate New Price for Preview
    const calculateNewPrice = (price: number) => {
        if (bulkEditConfig.type === 'percent_inc') return Math.round(price * (1 + bulkEditConfig.value / 100));
        if (bulkEditConfig.type === 'percent_dec') return Math.round(price * (1 - bulkEditConfig.value / 100));
        if (bulkEditConfig.type === 'amount_inc') return price + bulkEditConfig.value;
        if (bulkEditConfig.type === 'amount_dec') return price - bulkEditConfig.value;
        return price;
    };

    const handleApplyBulkEdit = () => {
        if (selectedBulkEditProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");
