        const newHistory = {
            id: `ph-${Date.now()}`,
            time: new Date().toLocaleString('vi-VN'),
            action: actionText,
            count: selectedBulkEditProducts.length,
            user: 'Admin', // In real app, use currentUser.name
            status: 'success'
