  const renderBulkEdit = () => {
    // Filter Products Logic
    const filteredProducts = MOCK_PRODUCTS.filter(p => 
        p.name.toLowerCase().includes(bulkEditSearch.toLowerCase()) || 
        p.sku.toLowerCase().includes(bulkEditSearch.toLowerCase())
    );

    const toggleSelection = (id: string) => {
        setSelectedBulkEditProducts(prev => 
            prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
        );
    };

    const toggleSelectAll = () => {
        if (selectedBulkEditProducts.length === filteredProducts.length) {
            setSelectedBulkEditProducts([]);
        } else {
            setSelectedBulkEditProducts(filteredProducts.map(p => p.id));
        }
    };

    // Calculate New Price for Preview
    const calculateNewPrice = (price: number) => {
        if (bulkEditConfig.type === 'percent_inc') return Math.round(price * (1 + bulkEditConfig.value / 100));
        if (bulkEditConfig.type === 'percent_dec') return Math.round(price * (1 - bulkEditConfig.value / 100));
        if (bulkEditConfig.type === 'amount_inc') return price + bulkEditConfig.value;
        if (bulkEditConfig.type === 'amount_dec') return price - bulkEditConfig.value;
        return price;
    };

    const handleApplyBulkEdit = () => {
        if (selectedBulkEditProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");
        if (bulkEditConfig.value <= 0) return alert("Giá trị điều chỉnh phải lớn hơn 0.");

        const actionText = bulkEditConfig.type.includes('percent') 
            ? `${bulkEditConfig.type.includes('inc') ? 'Tăng' : 'Giảm'} ${bulkEditConfig.value}%`
            : `${bulkEditConfig.type.includes('inc') ? 'Tăng' : 'Giảm'} ${formatCurrency(bulkEditConfig.value)}`;

        // Mock detail data generation
        const productsChanged = MOCK_PRODUCTS.filter(p => selectedBulkEditProducts.includes(p.id));
        const historyDetails = productsChanged.map(p => ({
            id: p.id,
            name: p.name,
            image: p.image,
            oldPrice: p.price,
            newPrice: calculateNewPrice(p.price)
        }));

        const newHistory = {
            id: `ph-${Date.now()}`,
            time: new Date().toLocaleString('vi-VN'),
            action: actionText,
            count: selectedBulkEditProducts.length,
            user: 'Admin', // In real app, use currentUser.name
            status: 'success',
            details: historyDetails
        };

        setPriceHistory(prev => [newHistory, ...prev]);
        setSelectedBulkEditProducts([]);
        alert("Đã cập nhật giá thành công! Kiểm tra lịch sử bên phải.");
    };

