// Reusable Pagination Component
const PaginationControl = ({ 
  currentPage, 
  totalItems, 
  pageSize, 
  onPageChange,
  simple = false 
}: { 
  currentPage: number, 
  totalItems: number, 
  pageSize: number, 
  onPageChange: (page: number) => void,
  simple?: boolean
}) => {
  const totalPages = Math.ceil(totalItems / pageSize);
  if (totalPages <= 1) return null;

  return (
    <div className={`flex items-center justify-between mt-4 ${simple ? 'text-xs' : 'text-sm'} border-t border-slate-100 pt-3`}>
      <span className="text-slate-500">
        {simple ? `${currentPage}/${totalPages}` : `Trang ${currentPage} / ${totalPages}`}
      </span>
      <div className="flex gap-1">
        <button 
          onClick={() => onPageChange(Math.max(1, currentPage - 1))}
          disabled={currentPage === 1}
          className="p-1 hover:bg-slate-100 rounded disabled:opacity-30 disabled:cursor-not-allowed"
        >
          <ChevronLeft size={simple ? 14 : 18}/>
        </button>
        <button 
          onClick={() => onPageChange(Math.min(totalPages, currentPage + 1))}
          disabled={currentPage === totalPages}
          className="p-1 hover:bg-slate-100 rounded disabled:opacity-30 disabled:cursor-not-allowed"
        >
          <ChevronRight size={simple ? 14 : 18}/>
        </button>
      </div>
    </div>
  );
};

