  const renderBulkEdit = () => {
    // Filter Products Logic
    const filteredProducts = MOCK_PRODUCTS.filter(p => 
        p.name.toLowerCase().includes(bulkEditSearch.toLowerCase()) || 
        p.sku.toLowerCase().includes(bulkEditSearch.toLowerCase())
    );

    // Slicing
    const indexOfLastItem = bulkEditPage * ITEMS_PER_PAGE;
    const indexOfFirstItem = indexOfLastItem - ITEMS_PER_PAGE;
    const currentProducts = filteredProducts.slice(indexOfFirstItem, indexOfLastItem);

    const indexOfLastHistory = bulkEditHistoryPage * HISTORY_PAGE_SIZE;
    const indexOfFirstHistory = indexOfLastHistory - HISTORY_PAGE_SIZE;
    const currentHistory = priceHistory.slice(indexOfFirstHistory, indexOfLastHistory);

    const toggleSelection = (id: string) => {
        setSelectedBulkEditProducts(prev => 
            prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
        );
    };

    const toggleSelectAll = () => {
        if (selectedBulkEditProducts.length === currentProducts.length) {
            setSelectedBulkEditProducts([]);
        } else {
            // Select only visible page items to avoid confusion with pagination
            setSelectedBulkEditProducts(currentProducts.map(p => p.id));
        }
    };

    // Calculate New Price for Preview
    const calculateNewPrice = (price: number) => {
        if (bulkEditConfig.type === 'percent_inc') return Math.round(price * (1 + bulkEditConfig.value / 100));
        if (bulkEditConfig.type === 'percent_dec') return Math.round(price * (1 - bulkEditConfig.value / 100));
        if (bulkEditConfig.type === 'amount_inc') return price + bulkEditConfig.value;
        if (bulkEditConfig.type === 'amount_dec') return price - bulkEditConfig.value;
        return price;
    };

    const handleApplyBulkEdit = () => {
        if (selectedBulkEditProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");
        if (bulkEditConfig.value <= 0) return alert("Giá trị điều chỉnh phải lớn hơn 0.");

        const actionText = bulkEditConfig.type.includes('percent') 
            ? `${bulkEditConfig.type.includes('inc') ? 'Tăng' : 'Giảm'} ${bulkEditConfig.value}%`
            : `${bulkEditConfig.type.includes('inc') ? 'Tăng' : 'Giảm'} ${formatCurrency(bulkEditConfig.value)}`;

        // Mock detail data generation
        const productsChanged = MOCK_PRODUCTS.filter(p => selectedBulkEditProducts.includes(p.id));
        const historyDetails = productsChanged.map(p => ({
            id: p.id,
            name: p.name,
            image: p.image,
            oldPrice: p.price,
            newPrice: calculateNewPrice(p.price)
        }));

        const newHistory = {
            id: `ph-${Date.now()}`,
            time: new Date().toLocaleString('vi-VN'),
            action: actionText,
            count: selectedBulkEditProducts.length,
            user: 'Admin', // In real app, use currentUser.name
            status: 'success',
            details: historyDetails
        };

        setPriceHistory(prev => [newHistory, ...prev]);
        setSelectedBulkEditProducts([]);
        alert("Đã cập nhật giá thành công! Kiểm tra lịch sử bên phải.");
    };

    return (
    <div className="space-y-6 animate-fade-in h-full flex flex-col">
       <InstructionBox 
          title="Chỉnh sửa giá hàng loạt"
          steps={[
             "Bước 1: Lọc và chọn các sản phẩm cần điều chỉnh giá.",
             "Bước 2: Chọn loại điều chỉnh (Tăng/Giảm theo % hoặc Số tiền).",
             "Bước 3: Nhập giá trị mong muốn và kiểm tra cột 'Giá mới'.",
             "Bước 4: Nhấn 'Áp dụng' để cập nhật giá đồng loạt."
          ]}
       />

       <div className="grid grid-cols-1 xl:grid-cols-5 gap-6 h-full">
           {/* Main Area */}
           <div className="xl:col-span-4 flex flex-col gap-4">
                {/* Control Panel */}
                <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-end">
                    <div className="flex-1 min-w-[200px]">
                        <label className="block text-sm font-bold text-slate-700 mb-1">Loại điều chỉnh</label>
                        <div className="relative">
                            <select 
                                value={bulkEditConfig.type}
                                onChange={(e) => setBulkEditConfig({...bulkEditConfig, type: e.target.value as any})}
                                className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500 appearance-none bg-slate-50"
                            >
                                <option value="percent_inc">Tăng giá theo %</option>
                                <option value="percent_dec">Giảm giá theo %</option>
                                <option value="amount_inc">Tăng giá theo số tiền (VND)</option>
                                <option value="amount_dec">Giảm giá theo số tiền (VND)</option>
                            </select>
                            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16}/>
                        </div>
                    </div>
                    <div className="flex-1 min-w-[150px]">
                        <label className="block text-sm font-bold text-slate-700 mb-1">Giá trị</label>
                        <input 
                            type="number" 
                            value={bulkEditConfig.value}
                            onChange={(e) => setBulkEditConfig({...bulkEditConfig, value: Number(e.target.value)})}
                            className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 font-bold text-indigo-600"
                            placeholder="Nhập số..."
                        />
                    </div>
                    <button 
                        onClick={handleApplyBulkEdit}
                        className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold shadow-sm hover:bg-indigo-700 flex items-center gap-2"
                    >
                        <Save size={18} /> Áp dụng
                    </button>
                </div>

                {/* Search Bar */}
                <div className="relative">
                    <input 
                        type="text" 
                        placeholder="Tìm sản phẩm để sửa giá..." 
                        value={bulkEditSearch}
                        onChange={(e) => setBulkEditSearch(e.target.value)}
                        className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                </div>

                {/* Product Table */}
                <div className="flex-1 bg-white border border-slate-200 rounded-xl shadow-sm overflow-hidden flex flex-col">
                    <div className="overflow-auto flex-1 h-[400px]"> {/* Fixed height for scrolling */}
                        <table className="w-full text-sm text-left">
                            <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200 sticky top-0 z-10 shadow-sm">
                                <tr>
                                    <th className="px-4 py-3 w-10 text-center">
                                        <input 
                                            type="checkbox" 
                                            checked={selectedBulkEditProducts.length > 0 && selectedBulkEditProducts.length === currentProducts.length}
                                            onChange={toggleSelectAll}
                                            className="rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
