                                    </th>
                                    <th className="px-4 py-3">Sản phẩm</th>
                                    <th className="px-4 py-3 text-right">Giá hiện tại</th>
                                    <th className="px-4 py-3 text-center"></th>
                                    <th className="px-4 py-3 text-right text-indigo-600 font-bold bg-indigo-50">Giá mới</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {currentProducts.map(p => {
                                    const isSelected = selectedBulkEditProducts.includes(p.id);
                                    const newPrice = calculateNewPrice(p.price);

                                    return (
                                    <tr key={p.id} className={`hover:bg-slate-50 transition-colors ${isSelected ? 'bg-indigo-50/20' : ''}`}>
                                        <td className="px-4 py-3 text-center">
                                            <input 
                                                type="checkbox" 
                                                checked={isSelected}
                                                onChange={() => toggleSelection(p.id)}
                                                className="rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                                            />
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-3">
                                                <img src={p.image} className="w-10 h-10 rounded object-cover border border-slate-200 bg-white" />
                                                <div>
                                                    <div className="font-medium text-slate-800 line-clamp-1">{p.name}</div>
                                                    <div className="text-xs text-slate-500">{p.sku}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3 text-right font-medium text-slate-600">{formatCurrency(p.price)}</td>
                                        <td className="px-4 py-3 text-center text-slate-300">
                                            <ArrowRight size={16} />
                                        </td>
                                        <td className="px-4 py-3 text-right font-bold text-indigo-600 bg-indigo-50/30">
                                            {formatCurrency(newPrice)}
                                            {newPrice !== p.price && (
                                                <span className={`text-[10px] ml-1 ${newPrice > p.price ? 'text-green-600' : 'text-red-600'}`}>
                                                    {newPrice > p.price ? <TrendingUp size={10} className="inline"/> : <TrendingDown size={10} className="inline"/>}
                                                </span>
                                            )}
                                        </td>
                                    </tr>
