                                        {h.status === 'success' ? 'Thành công' : 'Một phần'}
                                    </span>
                                    <span className="text-[10px] text-slate-400">{h.time}</span>
                                </div>
                                <div className="text-xs text-slate-600 space-y-1">
                                    <div className="font-bold text-slate-800">Đăng {h.count} sản phẩm</div>
                                    <div className="flex items-center gap-1 text-slate-500">
                                        Lên: {h.platforms.join(', ')}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                    <PaginationControl 
                        currentPage={listingHistoryPage}
                        totalItems={MOCK_PUBLISH_HISTORY.length}
                        pageSize={HISTORY_PAGE_SIZE}
                        onPageChange={setListingHistoryPage}
                        simple
                    />
                </div>
           </div>
       </div>
       {renderEditListingModal()}
    </div>
  )};

  const renderListingWizard = () => {
    if (!isListingModalOpen) return null;

    // Filter available products for Step 3 based on source
    // For 'system', we use MOCK_PRODUCTS. For 'shop', we might filter or simulate.
    const productsToSelect = MOCK_PRODUCTS; 

    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center backdrop-blur-sm p-4 animate-fade-in">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl overflow-hidden h-[85vh] flex flex-col">
          {/* Header */}
          <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-50">
             <div className="flex items-center gap-2">
                <UploadCloud size={20} className="text-indigo-600"/>
                <div>
                   <h3 className="font-bold text-lg text-indigo-900">Đăng bán đa sàn</h3>
                   <p className="text-xs text-indigo-700">Bước {listingStep}/4: {
                      listingStep === 1 ? 'Chọn nguồn dữ liệu' :
                      listingStep === 2 ? 'Chọn sàn đăng bán' :
                      listingStep === 3 ? 'Chọn sản phẩm' : 'Chỉnh sửa thông tin'
                   }</p>
                </div>
             </div>
             <button onClick={resetListingWizard} className="text-slate-400 hover:text-slate-600"><X size={20}/></button>
          </div>

          {/* Content */}
          <div className="flex-1 overflow-y-auto p-6">
             {listingStep === 1 && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                   <button 
                     onClick={() => setListingSource('system')}
                     className={`p-6 rounded-xl border-2 flex flex-col items-center gap-3 transition-all ${listingSource === 'system' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 hover:border-indigo-300 text-slate-600'}`}
                   >
                      <Database size={32} />
                      <span className="font-bold">Từ kho hệ thống</span>
                      <span className="text-xs text-center font-normal">Sử dụng dữ liệu sản phẩm có sẵn trên OmniSales</span>
                   </button>
                   <button 
                     onClick={() => setListingSource('shop')}
                     className={`p-6 rounded-xl border-2 flex flex-col items-center gap-3 transition-all ${listingSource === 'shop' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 hover:border-indigo-300 text-slate-600'}`}
                   >
                      <Store size={32} />
                      <span className="font-bold">Sao chép từ Shop khác</span>
                      <span className="text-xs text-center font-normal">Clone sản phẩm từ gian hàng đã kết nối</span>
                   </button>
                   <button 
                     onClick={() => setListingSource('link')}
                     className={`p-6 rounded-xl border-2 flex flex-col items-center gap-3 transition-all ${listingSource === 'link' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 hover:border-indigo-300 text-slate-600'}`}
                   >
                      <LinkIcon size={32} />
                      <span className="font-bold">Từ đường dẫn (Link)</span>
                      <span className="text-xs text-center font-normal">Dán link sản phẩm Shopee/Lazada/TikTok</span>
                   </button>

                   {listingSource === 'link' && (
                      <div className="md:col-span-3 mt-4 animate-fade-in">
                         <div className="flex gap-2">
                            <input 
                              type="text" 
                              value={listingLinkUrl}
                              onChange={(e) => setListingLinkUrl(e.target.value)}
                              placeholder="Dán link sản phẩm tại đây..."
                              className="flex-1 border border-slate-200 rounded-lg px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                            />
                            <button 
                              onClick={handleAnalyzeLink}
                              disabled={isAnalyzingLink}
                              className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold shadow-sm hover:bg-indigo-700 disabled:bg-slate-300 flex items-center gap-2"
                            >
                               {isAnalyzingLink && <Loader2 size={16} className="animate-spin"/>} Phân tích
                            </button>
                         </div>
                         <p className="text-xs text-slate-500 mt-2 ml-1">Hỗ trợ: Shopee, Lazada, TikTok Shop, Tiki</p>
                      </div>
                   )}
                </div>
             )}

             {listingStep === 2 && (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                   {allShops.map(shop => (
                      <div 
                        key={shop.id} 
                        onClick={() => toggleListingShop(shop.id)}
                        className={`flex items-center gap-3 p-4 rounded-xl border-2 cursor-pointer transition-all ${listingSelectedShops.includes(shop.id) ? 'border-indigo-600 bg-indigo-50 shadow-sm' : 'border-slate-200 hover:border-indigo-300'}`}
                      >
                         <div className={`w-6 h-6 rounded-full border flex items-center justify-center ${listingSelectedShops.includes(shop.id) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-300 bg-white'}`}>
                            {listingSelectedShops.includes(shop.id) && <Check size={14}/>}
                         </div>
                         <div className="flex-1">
                            <div className="font-bold text-slate-800">{shop.name}</div>
                            <div className="text-xs text-slate-500 flex items-center gap-1 mt-0.5">
                               {LOGOS[shop.platform] && <img src={LOGOS[shop.platform]} className="w-3 h-3 object-contain"/>} {shop.platform}
                            </div>
                         </div>
                      </div>
                   ))}
                </div>
             )}

             {listingStep === 3 && (
                <div className="border border-slate-200 rounded-xl overflow-hidden">
                   <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
                         <tr>
                            <th className="px-4 py-3 w-10 text-center">
                               <input type="checkbox" className="rounded text-indigo-600 focus:ring-indigo-500"/>
                            </th>
                            <th className="px-4 py-3">Sản phẩm</th>
                            <th className="px-4 py-3 text-right">Giá gốc</th>
                            <th className="px-4 py-3 text-center">Tồn kho</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                         {productsToSelect.map(p => {
                            const isSelected = listingSelectedProducts.includes(p.id);
                            return (
                               <tr key={p.id} className={`hover:bg-slate-50 cursor-pointer ${isSelected ? 'bg-indigo-50/30' : ''}`} onClick={() => toggleListingProduct(p.id)}>
                                  <td className="px-4 py-3 text-center">
                                     <input 
                                       type="checkbox" 
                                       checked={isSelected}
                                       readOnly
                                       className="rounded text-indigo-600 focus:ring-indigo-500 pointer-events-none"
                                     />
                                  </td>
                                  <td className="px-4 py-3">
                                     <div className="flex items-center gap-3">
                                        <img src={p.image} className="w-10 h-10 rounded object-cover border border-slate-200" />
                                        <div>
                                           <div className="font-medium text-slate-800 line-clamp-1">{p.name}</div>
                                           <div className="text-xs text-slate-500">{p.sku}</div>
                                        </div>
                                     </div>
                                  </td>
                                  <td className="px-4 py-3 text-right text-slate-600 font-medium">{formatCurrency(p.price)}</td>
                                  <td className="px-4 py-3 text-center text-slate-600">{p.stock}</td>
                               </tr>
                            )
                         })}
                      </tbody>
                   </table>
                </div>
             )}

             {listingStep === 4 && (
                <div className="space-y-6">
                   <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-3 text-xs text-yellow-800 flex gap-2">
                      <AlertCircle size={16} className="shrink-0 mt-0.5"/>
                      <div>
                         <strong>Lưu ý:</strong> Giá và tồn kho dưới đây sẽ được áp dụng cho tất cả {listingSelectedShops.length} gian hàng đã chọn.
                      </div>
                   </div>

                   <div className="border border-slate-200 rounded-xl overflow-hidden">
                      <table className="w-full text-sm text-left">
                         <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
                            <tr>
                               <th className="px-4 py-3">Sản phẩm</th>
                               <th className="px-4 py-3 w-40 text-right">Giá bán</th>
                               <th className="px-4 py-3 w-32 text-center">Tồn kho</th>
                            </tr>
                         </thead>
                         <tbody className="divide-y divide-slate-100">
                            {listingSelectedProducts.map(pid => {
                               const product = productsToSelect.find(p => p.id === pid);
                               if (!product) return null;
                               const editData = listingEdits[pid] || { price: product.price, stock: product.stock };

                               return (
                                  <tr key={pid} className="hover:bg-slate-50">
                                     <td className="px-4 py-3">
                                        <div className="flex items-center gap-3">
                                           <img src={product.image} className="w-10 h-10 rounded object-cover border border-slate-200" />
                                           <div className="font-medium text-slate-800 line-clamp-2 max-w-xs">{product.name}</div>
                                        </div>
                                     </td>
                                     <td className="px-4 py-3 text-right">
                                        <input 
                                          type="text" // Use text for formatting
                                          value={formatInputNumber(editData.price)}
                                          onChange={(e) => handleListingEditChange(pid, 'price', e.target.value)}
                                          className="w-full text-right border border-slate-200 rounded px-2 py-1 font-medium text-indigo-600 focus:ring-1 focus:ring-indigo-500 outline-none"
                                        />
                                     </td>
                                     <td className="px-4 py-3 text-center">
                                        <input 
                                          type="number" 
                                          value={editData.stock}
                                          onChange={(e) => handleListingEditChange(pid, 'stock', e.target.value)}
                                          className="w-full text-center border border-slate-200 rounded px-2 py-1 font-medium text-slate-800 focus:ring-1 focus:ring-indigo-500 outline-none"
                                        />
                                     </td>
                                  </tr>
                               );
                            })}
                         </tbody>
                      </table>
                   </div>
                </div>
             )}
          </div>

          {/* Footer */}
          <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
             <div className="text-sm text-slate-500">
                {listingStep === 2 && `Đã chọn ${listingSelectedShops.length} gian hàng`}
                {listingStep === 3 && `Đã chọn ${listingSelectedProducts.length} sản phẩm`}
             </div>
             <div className="flex gap-2">
                {listingStep > 1 && (
                   <button 
                     onClick={() => setListingStep(listingStep - 1)}
                     className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-100"
                   >
                      Quay lại
                   </button>
                )}
                {listingStep < 4 ? (
                   <button 
                     onClick={() => {
                        if (listingStep === 1 && listingSource === 'link' && !isAnalyzingLink && listingSelectedProducts.length === 0) return alert("Vui lòng phân tích link trước.");
                        if (listingStep === 2 && listingSelectedShops.length === 0) return alert("Vui lòng chọn ít nhất 1 gian hàng.");
                        if (listingStep === 3 && listingSelectedProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");
                        setListingStep(listingStep + 1);
                     }}
                     className="px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-700 flex items-center gap-2"
                   >
                      Tiếp tục <ChevronRight size={16}/>
                   </button>
                ) : (
                   <button 
                     onClick={handlePublishListing}
                     className="px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-700 flex items-center gap-2"
                   >
                      <Rocket size={16} /> Đăng ngay
                   </button>
                )}
             </div>
          </div>
        </div>
      </div>
    );
  };

  const renderEditListingModal = () => {
      if (!editingListing) return null;

      return (
          <div className="fixed inset-0 bg-black/60 z-[80] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
              <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden">
                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                      <h3 className="font-bold text-slate-800">Chỉnh sửa sản phẩm đã đăng</h3>
                      <button onClick={() => setEditingListing(null)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                  </div>

                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div className="flex gap-4 items-start pb-4 border-b border-slate-100">
                          <img src={editingListing.image} className="w-16 h-16 rounded object-cover border border-slate-200" />
                          <div>
                              <div className="font-bold text-slate-800 text-sm mb-1">{editingListing.productName}</div>
                              <div className="flex gap-1 flex-wrap">
                                  {editingListing.platforms.map((p: any) => (
                                      <div key={p} className="w-6 h-6 rounded-full border border-slate-200 flex items-center justify-center bg-white p-0.5">
                                          <PlatformIcon platform={p} />
                                      </div>
                                  ))}
                              </div>
                          </div>
                      </div>

                      <div className="bg-indigo-50 p-3 rounded-lg text-xs text-indigo-700 flex gap-2">
                          <Info size={16} className="shrink-0 mt-0.5"/>
                          <span>Thay đổi tại đây sẽ cập nhật đồng bộ lên tất cả các sàn mà sản phẩm này đang liên kết.</span>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Giá bán (VND)</label>
                              <input 
                                  type="number" 
                                  value={editingListing.price || 0}
                                  onChange={(e) => setEditingListing({...editingListing, price: Number(e.target.value)})}
                                  className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 focus:border-indigo-500 font-bold text-slate-800"
                              />
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Tồn kho</label>
                              <input 
                                  type="number" 
                                  value={editingListing.stock || 0}
                                  onChange={(e) => setEditingListing({...editingListing, stock: Number(e.target.value)})}
                                  className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 focus:border-indigo-500 font-bold text-slate-800"
                              />
                          </div>
                      </div>

                      <div>
                          <label className="block text-sm font-bold text-slate-700 mb-1">Tên sản phẩm trên sàn</label>
                          <input 
                              type="text" 
                              value={editingListing.productName}
                              onChange={(e) => setEditingListing({...editingListing, productName: e.target.value})}
                              className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 focus:border-indigo-500"
                          />
                      </div>
                  </div>

                  <div className="p-4 border-t border-slate-100 flex justify-end gap-2 bg-slate-50">
                      <button onClick={() => setEditingListing(null)} className="px-4 py-2 border border-slate-200 bg-white rounded-lg text-slate-600 hover:bg-slate-100 text-sm font-medium">Hủy</button>
                      <button onClick={handleSaveListing} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-bold shadow-sm">Lưu thay đổi</button>
                  </div>
              </div>
          </div>
      );
  };

  return (
    <div className="pb-10">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Công cụ quản lý</h2>
        <p className="text-sm text-slate-500">Đồng bộ và quản lý dữ liệu sản phẩm trên diện rộng.</p>
      </div>

      {/* Navigation Tabs (Top) */}
      <div className="flex overflow-x-auto no-scrollbar gap-2 mb-6 bg-white p-2 rounded-xl border border-slate-100 shadow-sm">
        {tabs.map(tab => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                isActive 
                  ? 'bg-indigo-600 text-white shadow-md' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <Icon size={18} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Content Area */}
      <div>
         {activeTab === 'import' && renderProductImport()}
         {activeTab === 'listing' && renderListingTool()}
         {activeTab === 'sync' && renderShopSync()}
         {activeTab === 'bulkedit' && renderBulkEdit()}
         {activeTab === 'keywords' && renderForbiddenKeywords()}
      </div>

      {/* Listing Wizard Modal */}
      {renderListingWizard()}

      {/* Import Progress Modal */}
      {renderImportProgressModal()}

      {/* History Detail Modal */}
      {renderHistoryDetailModal()}

      {/* Price History Modal */}
      {renderPriceHistoryModal()}

      {/* Publish Progress Modal */}
      {renderPublishProgressModal()}

      {/* Sync Progress Modal */}
      {renderSyncProgressModal()}
    </div>
  );
};

export default Tools;
